%[text] # **Hava Kalitesi ve Kirlilik Analizi**
%%
%[text] ## 1. Veriyi içe aktarma
data = readtable('AirQuality.csv', 'PreserveVariableNames', true, 'Delimiter', ';', 'DecimalSeparator', ',');
data = data(:,1:15); % gereksiz son sütunları temizle.
%[text] ## 2. Eksik verileri doldurma - Interpolation
data_raw = data; % temizlenmemiş veriyi sakla.
rawDate = string(data.Date);
rawTime = string(data.Time);
DateTimeStr = rawDate + " " + rawTime;

TimeAxis = datetime(DateTimeStr, 'InputFormat', 'dd/MM/yyyy HH.mm.ss', 'Locale', 'en_US'); % tarih ve saat sütunlarını birleştirme.
[TimeAxis, sortIdx] = sort(TimeAxis);
data = data(sortIdx, :);
data_raw = data_raw(sortIdx, :);

numericVars = data.Properties.VariableNames(3:end); % tarih ve saat hariç sütunları al.
data_clean = fillmissing(data, 'linear', 'DataVariables', numericVars); % lineer interpolasyon ile eksikleri doldurma.
%%
%[text] ## 3. Görselleştirme
% örnek CO verisini görselleştirelim.
figure; %[output:498b2dc0]
subplot(2,1,1); %[output:498b2dc0]
plot(TimeAxis, data_raw.("CO(GT)"), 'r'); %[output:498b2dc0]
title('Ham Veri') %[output:498b2dc0]
xlabel('Zaman'); %[output:498b2dc0]
ylabel('CO Değeri'); %[output:498b2dc0]
grid on; %[output:498b2dc0]

subplot(2,1,2); %[output:498b2dc0]
plot(TimeAxis, data_clean.("CO(GT)"), 'b-'); %[output:498b2dc0]
title('Temizlenmiş Veri'); %[output:498b2dc0]
xlabel('Zaman'); %[output:498b2dc0]
ylabel('CO Değeri'); %[output:498b2dc0]
grid on; %[output:498b2dc0]
%%
%[text] ## 4. Özdeğer - Özvektör Analizi (PCA)
% veriyi matrise çevir
X_raw = table2array(data_clean(:, 3:end));
varNames = data_clean.Properties.VariableNames(3:end); % tarih-saat sütununu at.

% normalizasyon, ölçeklendirme, Z-score
X_norm = zscore(X_raw);

% kovaryans matrisi hesabı
covMatrix = cov(X_norm);

figure; %[output:31449c1d]
h = heatmap(numericVars, numericVars, covMatrix); %[output:31449c1d]

% özdeğer - özvektör hesabı
[V, D] = eig(covMatrix);

% sıralamayı büyükten küçüğe çevirme.
[eigenvalues, idx] = sort(diag(D), 'descend');
eigenvectors = V(:, idx);

% varyans açıklama oranları
total_var = sum(eigenvalues);
explained_var = (eigenvalues/total_var)*100;
cumulative_var = cumsum(explained_var);

disp('--- PCA Sonuçları---'); %[output:905a549e]
fprintf('1. Temel bileşen (PC1) varyansın %% %.2f kısmını açıklıyor.', explained_var(1)); %[output:23772d77]
fprintf('İlk 2 bileşen toplam varyansın %% %.2f kısmını açıklıyor.', cumulative_var(2)); %[output:5ea19cf8]
%%
%[text] ## 5. Görselleştirme
% Scree Plot - Yamaç Grafiği
figure; %[output:103f4b9e]
subplot(2,1,1); %[output:103f4b9e]
bar(explained_var); %[output:103f4b9e]
title('Scree Plot: Bileşenlerin Varyans Açıklama Oranları'); %[output:103f4b9e]
xlabel('Bileşen Numarası'); %[output:103f4b9e]
ylabel('Açıklanan Varyans (%)'); %[output:103f4b9e]
grid on; %[output:103f4b9e]

% verinin tek boyuta indirgenmiş hali (PC1 Zaman Serisi)
PC1 = X_norm * eigenvectors(:, 1);

subplot(2,1,2); %[output:103f4b9e]
plot(TimeAxis, PC1, 'k--'); %[output:103f4b9e]
title('Genel Hava Kirliliği İndexi (1. Temel Bileşen - PC1)'); %[output:103f4b9e]
xlabel('Zaman'); %[output:103f4b9e]
ylabel('PC1 Değeri (Normalize)'); %[output:103f4b9e]
grid on; %[output:103f4b9e]

% değişkenleri kaydet.
save('pca_results.mat', 'PC1', 'TimeAxis', 'eigenvalues', 'explained_var');
%%
%[text] ## 6. Eğri Uydurma
load('pca_results.mat'); % kaydedilen sonuçları yükle.

% zaman eksenini sayısallaştırma
t_numeric = hours(TimeAxis-TimeAxis(1));

% eğri uydurma - en küçük kareler yöntemi
pol_deg = 10;
[p, S, mu] = polyfit(t_numeric, PC1, pol_deg);

%%
%[text] ## 7. Doğrusal Olmayan Denklem Çözümü: Kritik Eşik Analizi
esik_deger = 2.0;
p_esik = p;
p_esik(end) = p_esik(end) - esik_deger;

kokler = roots(p_esik);
kokler_gercek = kokler * mu(2) + mu(1);
zaman_noktalari = kokler(imag(kokler_gercek)==0 & kokler_gercek>=0 & kokler_gercek<=max(t_numeric));
zaman_noktalari = sort(zaman_noktalari);

fprintf('Kirlilik indexi %0.1f değerini şu saatlerde kesmektedir:\n', esik_deger); %[output:1ed46c3c]
disp(zaman_noktalari);

hold on; %[output:9ca27fcc]
yline(esik_deger, '--r', 'Kritik Eşik'); %[output:9ca27fcc]
plot(zaman_noktalari, repmat(esik_deger, size(zaman_noktalari)), 'ko', 'MarkerFaceColor', 'y');
hold off; %[output:9ca27fcc]
%%
%[text] ## 8. Sayısal İntegral
% pürüzsüz veriyi üretelim.
y_fit = polyval(p, t_numeric, S, mu);

% sayısal integral alma.
toplam_kirlilik = trapz(t_numeric, abs(y_fit));

fprintf("\n--- Modelleme Sonuçları ---\n"); %[output:43129828]
fprintf('Uydurulan Polinom Derecesi: %d\n', pol_deg); %[output:87909795]
fprintf('Hesaplanan Toplam Kirlilik Yükü (İntegral Alanı): %.2f birim\n', toplam_kirlilik); %[output:2b64bc96]
%%
%[text] ## 9. Son Grafik
figure('Name', 'Final Model', 'Color', 'w'); %[output:18d0ae3e]

% gerçek PC1 verisi
plot(t_numeric, PC1, '.', 'Color', [0.7 0.7 0.7], 'MarkerSize', 4, 'DisplayName', 'Ham PCA Verisi (Gürültülü)'); %[output:18d0ae3e]
hold on; %[output:18d0ae3e]

% uydurduğumuz matematiksel model
plot(t_numeric, y_fit, 'r-', 'LineWidth', 2, 'DisplayName', 'Matematiksel Model (Polinom Fit)'); %[output:18d0ae3e]

% integral alanı
area(t_numeric, abs(y_fit), 'FaceAlpha', 0.1, 'FaceColor', 'r', 'DisplayName', ['Kümülatif Yük: ' num2str(toplam_kirlilik, '%.0f')]); %[output:18d0ae3e]

title('Şehir Hava Kirliliği Modellemesi ve Toplam Maruziyet'); %[output:18d0ae3e]
xlabel('Zaman (Saat)'); %[output:18d0ae3e]
ylabel('Kirlilik İndeksi (PC1)'); %[output:18d0ae3e]
legend('Location', 'best'); %[output:18d0ae3e]
grid on; %[output:18d0ae3e]

